#include<bits/stdc++.h>
#define int long long
#define PII pair<int,int>
#define p_q priority_queue
#define CI const int
#define pb push_back
#define mk make_pair
#define inf 0x3f3f3f3f3f3f3f3f
#define FOR(a,b,c) for(int a=b;a<=c;++a)
#define ROF(a,b,c) for(int a=b;a>=c;--a)
using namespace std;
bool cmp(const int &a,const int &b)
{
	return a>b;
}
CI MAXN=1e5+5;
int n,m,a[MAXN],d,x,cnt=0,num[105][105];
void solve()
{
	cin>>n>>m;
	FOR(i,1,n)
	{
		++cnt;
		if(cnt%2==1)
		{
			FOR(j,1,n)
			{
				++d;
				num[i][j]=d;
			}
		}
		if(cnt%2==0)
		{
			ROF(j,n,1)
			{
				++d;
				num[i][j]=d;
			}
		}
	}
	FOR(i,1,n*m)
	{
		cin>>a[i];
	}d=a[1];
	sort(a+1,a+n*m+1,cmp);
	FOR(i,1,n*m)
	{
		if(a[i]==d)
		{
			cnt=i;
		}
	}
	FOR(i,1,m)
	{
		FOR(j,1,n)
		{
			if(num[i][j]==cnt)
			{
				cout<<i<<' '<<j;
				return;
			}
		}
	}
}
signed main(void)
{

	//freopen("seat.in","r",stdin);
	//freopen("seat.out","w",stdout);
	int t=1;
	//cin>>t;
	while(t--)
	{
		solve();
	}
	return false;
}
